changeSet.sql:
UPDATE character_class SET caster_type='HALF', preparation='PREPARED'
    WHERE slug='artificer' AND homebrew_id IS NULL;
UPDATE character_class SET caster_type='FULL', preparation='KNOWN', ritual_casting=true
    WHERE slug='bard' AND homebrew_id IS NULL;
UPDATE character_class SET caster_type='FULL', preparation='PREPARED', ritual_casting=true
    WHERE slug='cleric' AND homebrew_id IS NULL;
UPDATE character_class SET caster_type='FULL', preparation='PREPARED', ritual_casting=true
    WHERE slug='druid' AND homebrew_id IS NULL;
UPDATE character_class SET caster_type='HALF', preparation='PREPARED'
    WHERE slug='paladin' AND homebrew_id IS NULL;
UPDATE character_class SET caster_type='HALF', preparation='KNOWN'
    WHERE slug='ranger' AND homebrew_id IS NULL;
UPDATE character_class SET caster_type='FULL', preparation='KNOWN'
    WHERE slug='sorcerer' AND homebrew_id IS NULL;
UPDATE character_class SET caster_type='PACT', preparation='KNOWN'
    WHERE slug='warlock' AND homebrew_id IS NULL;
UPDATE character_class SET caster_type='FULL', preparation='PREPARED', uses_spellbook=true, ritual_casting=true
    WHERE slug='wizard' AND homebrew_id IS NULL;
